public class Solution {
    private int[] counts, indices;

    public List<Integer> countSmaller(int[] nums) {
        int n = nums.length;
        counts  = new int[n];
        indices = new int[n];
        for (int i = 0; i < n; i++) indices[i] = i;
        mergeSort(nums, indices, 0, n - 1);
        List<Integer> result = new ArrayList<>();
        for (int c : counts) result.add(c);
        return result;
    }

    private void mergeSort(int[] nums, int[] idx, int l, int r) {
        if (l >= r) return;
        int mid = l + (r - l) / 2;
        mergeSort(nums, idx, l, mid);
        mergeSort(nums, idx, mid + 1, r);
        merge(nums, idx, l, mid, r);
    }

    private void merge(int[] nums, int[] idx, int l, int mid, int r) {
        int[] temp = new int[r - l + 1];
        int i = l, j = mid + 1, k = 0, rightCount = 0;
        while (i <= mid && j <= r) {
            if (nums[idx[j]] < nums[idx[i]]) {
                rightCount++;
                temp[k++] = idx[j++];
            } else {
                counts[idx[i]] += rightCount;
                temp[k++] = idx[i++];
            }
        }
        while (i <= mid) { counts[idx[i]] += rightCount; temp[k++] = idx[i++]; }
        while (j <= r) temp[k++] = idx[j++];
        System.arraycopy(temp, 0, idx, l, temp.length);
    }
}

