public class Solution {
    public void wiggleSort(int[] nums) {
        int n = nums.length;
        int[] sorted = nums.clone();
        Arrays.sort(sorted);
        int mid = (n - 1) / 2;
        int hi = n - 1;
        // Fill odd indices from n-1 downward (largest values)
        for (int i = 1; i < n; i += 2) nums[i] = sorted[hi--];
        // Fill even indices from mid downward (smaller values)
        for (int i = 0; i < n; i += 2) nums[i] = sorted[mid--];
    }
}

